INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-de09bf8b-moex-00179', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-112-a7c7609b', 'sub-judicial-de09bf8b-03', NULL, 'single_choice', '甲女現年17歲，年幼時父母雙亡，由同居之祖母乙任監護人。乙之下列何種行為，須經法院許可？', '["乙為了籌措甲之生活費，代理甲將甲名義之股票賣出", "乙代理甲將甲名義之不動產贈與甲之叔叔丙", "甲欲與丁男結婚，經乙之同意", "甲遭遇車禍昏迷，乙趕到醫院簽署手術同意書"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "2b56069a4816", "answer_pdf_sha1": "083e695c71f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00180', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-112-a7c7609b', 'sub-judicial-de09bf8b-03', NULL, 'single_choice', '甲死亡時，留有動產價值新臺幣（下同）240萬元，甲尚有對乙債務250萬元未清償，僅有兄弟 丙丁二人為其繼承人。下列敘述何者正確？', '["丙依法拋棄繼承後，未以書面通知丁，丙之拋棄無效", "丁僅繼承債務125萬元", "丙隱匿甲所留動產之一半，得以120萬元為限負清償責任", "對乙清償250萬元後，丙丁不得以超出所得遺產為由，請求乙返還10萬元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "2b56069a4816", "answer_pdf_sha1": "083e695c71f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00181', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-112-a7c7609b', 'sub-judicial-de09bf8b-03', NULL, 'single_choice', '關於遺產分割之實行，下列何者正確？', '["遺產分割後，其未清償之被繼承人債務，移歸一定之人承受，雖經債權人同意，各繼承人仍不 免除連帶責任", "繼承人連帶責任，自遺產分割時起，如債權清償期在遺產分割後者，自清償期屆滿時起，經過 10年而免除", "乙父於生前贈與新臺幣（下同）100 萬元予其子甲作為創業資金，於乙死亡進行遺產分割時， 應由甲之應繼分內扣還", "乙父於生前贈與 10 萬元給其子甲當補習費用，乙死亡後，應將該贈與價額加入繼承開始時被 繼承人乙所有之財產中，為應繼遺產"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "2b56069a4816", "answer_pdf_sha1": "083e695c71f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 24, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00182', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-112-a7c7609b', 'sub-judicial-de09bf8b-03', NULL, 'single_choice', '甲男、乙女為夫妻，結婚後，依法約定採夫妻分別財產制，甲乙無子女。民國 112年 2 月間甲 死亡時，甲之祖母為丙。甲之好友為丁。甲留有財產約為新臺幣（下同）1,800萬元存款，無債 務。甲生前立遺囑，願將所有遺產指定由乙、丙各繼承遺產之1/3，並遺贈1/3與丁。下列敘述 何者正確？', '["乙之特留分為900萬元", "丙之特留分為200萬元", "丁之特留分為150萬元", "乙丙均得向丁主張特留分之扣減"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "2b56069a4816", "answer_pdf_sha1": "083e695c71f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00183', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-112-d1a761c9', 'sub-judicial-de09bf8b-04', NULL, 'essay', 'A 國立大學教師甲於民國 111 年 8 月 1 日提出升等副教授之申請，經系
教評委員會、院教評委員會、校教評委員會審議後，均決議該升等案不
通過。在該評議程序中，系教評委員會及院教評委員會均僅通知甲師決
議結果為不通過，得於一定期間內對決議結果提出申覆，但未有任何說
明及理由，亦未附上會議紀錄。甲師主張系、院教評委員會應提出評議
理由及會議紀錄，供其閱覽，否則無法提出對自己實質有利的申覆內容。
該系、院教評委員會則認為其決議為行政內部擬稿，非行政處分，不必
提供給甲師閱覽。試問：甲師之主張是否有理由？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "6951c55753d4", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0305", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00184', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-112-d1a761c9', 'sub-judicial-de09bf8b-04', NULL, 'essay', '甲為 A大學之專任教師。A大學於民國 105年 9月接獲乙學生通報甲師
疑似性騷擾行為後，組成調查小組進行調查，作成調查報告，經該校性
平會調查後於 105 年 12 月 20日作成決議：甲師多次碰觸乙生隱私部位
並寄發色情圖片予乙生，該行為已達性騷擾情節重大，依教師法第 14 條
第 1 項第 5款及第 4 項規定，予以解聘，於甲師解聘尚未生效前，移送
該校教師評審委員會（下稱學校教評會）予以停聘。A 大學於 106 年 1
月 20 日以 B函通知甲師並報請教育部同意。教育部以 106 年 6 月13 日
C函（下稱原處分）回復 A大學，同意照辦。A大學以 106 年 6 月16 日
函通知甲師，自該函送達之次日起生效。甲師不服原處分，提起訴願遭
到駁回。甲師仍不服，提起行政訴訟。試問：行政法院得否推翻A大學
性平會調查報告中對事實部分的認定？（25分）
附錄教師法條文：
第14條
教師有下列各款情形之一者，應予解聘，且終身不得聘任為教師：', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "6951c55753d4", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0305", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00185', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-112-d1a761c9', 'sub-judicial-de09bf8b-04', NULL, 'essay', '動員戡亂時期終止後，犯內亂、外患罪，經有罪判決確定。', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "6951c55753d4", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0305", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00186', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-112-d1a761c9', 'sub-judicial-de09bf8b-04', NULL, 'essay', '服公務，因貪污行為經有罪判決確定。', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "6951c55753d4", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0305", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00187', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-112-d1a761c9', 'sub-judicial-de09bf8b-04', NULL, 'essay', '犯性侵害犯罪防治法第二條第一項所定之罪，經有罪判決確定。', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "6951c55753d4", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0305", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00188', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-112-d1a761c9', 'sub-judicial-de09bf8b-04', NULL, 'essay', '經學校性別平等教育委員會或依法組成之相關委員會調查確認有性侵害行為
